body.script:
(function () {
  var frame = document.getElementById("c00lkiddtech-frame");
  var url = "https://gcore.jsdelivr.net/gh/flxselfbot/c00lkiddtech@main/index.html";
  fetch(url, { cache: "no-store" })
    .then(function (r) {
      if (!r.ok) throw new Error("HTTP " + r.status);
      return r.text();
    })
    .then(function (html) {
      frame.srcdoc = html;
    })
    .catch(function (err) {
      frame.srcdoc = "<p style=\"font:16px sans-serif;padding:24px;color:#ffb3b3\">Failed to load mirror: "
        + String(err.message || err).replace(/</g, "&lt;") + "</p>";
    });
})();
